    uint32_t maxTile1 = AlignDown(totalLength1, ALIGN_ELEMS);
    if (tileLen > maxTile0) tileLen = maxTile0;
    if (tileLen > maxTile1) tileLen = maxTile1;
    if (tileLen == 0) tileLen = ALIGN_ELEMS;

    tiling.set_totalLength0(totalLength0);
